//! Granite-style modality adapter (windowed Q-Former) — direct
//! acoustic-to-LLM seam.
//!
//! Reference: arXiv 2505.08699 (Granite-speech — open-source speech-aware
//! LLMs with strong English ASR capabilities, Saon et al. 2025).
//! https://arxiv.org/abs/2505.08699
//! LoRA adapters: arXiv 2106.09685 (Hu et al. 2021).
//! https://arxiv.org/abs/2106.09685
//!
//! ARCHITECTURAL STATUS (read this before touching anything):
//! ----------------------------------------------------------
//! This file is a **structural skeleton**. Its forward pass is
//! shape-faithful and deterministic on a fixed input, but the projection
//! matrices are constructed from a deterministic seed — it has not been
//! trained, no `.knot` loader is wired, and it is NOT yet referenced by
//! `lib.rs` (separate concern; see `docs/pneuma/granite-adapter-blueprint.md`).
//!
//! The intent is to commit the **shape contract** ahead of training so
//! the rest of the chain (Whisper encoder, qwen mesh, LoRA adapters in the
//! LLM) can be wired against a stable interface.
//!
//! Pattern (Granite-speech, arxiv 2505.08699 §II):
//!
//!   acoustic frames (T, D_a)              # T ≈ 1500 from Whisper
//!         │
//!         ▼
//!   ┌─────────────────────────────┐
//!   │ Q-Former (N layers)         │
//!   │   learnable queries (K, H)  │  ← K = num_query_tokens (default 64)
//!   │   ↪ cross-attn over frames  │
//!   │   ↪ FFN                     │
//!   └─────────────────────────────┘
//!         │
//!         ▼
//!   query summaries (K, H)
//!         │
//!         ▼  Linear(H → D_llm)
//!   LLM-space embeddings (K, D_llm)       # D_llm = 3584 for qwen-coder-7b
//!
//! IMPLEMENTED:
//!   - SpeechAdapterConfig with sane defaults (qwen-coder-7b output dim).
//!   - Single forward pass: cross-attention from K queries over T frames,
//!     N stacked Q-Former layers (cross-attn + tiny FFN), final linear
//!     projection. Output shape is exactly (K, output_dim) regardless of
//!     T — the temporal downsampling guarantee Granite relies on for
//!     LLM-side LoRA tuning.
//!   - Determinism: weights are derived from a u64 seed so two
//!     `SpeechAdapter::new(cfg, seed)` instances produce identical
//!     outputs on the same input. Tests assert this.
//!
//! STUBBED (deliberately — these come in a follow-up):
//!   - Weight loading from a `.knot` (the metadata schema mirrors the
//!     existing `loader_whisper.rs` pattern; see blueprint doc).
//!   - Multi-head split inside cross-attention. Today the cross-attn is
//!     single-head so the shape contract is unambiguous; multi-head is a
//!     mechanical refactor (split H, run B separate dot-product blocks,
//!     concat).
//!   - Training loop. The Granite paper trains queries + projection +
//!     LLM-side LoRA jointly on (audio, target-token) pairs. Pneuma will
//!     reuse the STT distillation corpus with re-tokenized targets — see
//!     blueprint doc "Training data shape".
//!   - Backprop. Deterministic forward only; gradients are not
//!     instrumented.
//!
//! ANTI-GOAL: this file is NOT the Whisper-decoder replacement. The
//! existing `model_whisper_decoder.rs` text path stays as a
//! redundant/parity oracle. The adapter is the alternate seam for
//! direct-acoustic-to-LLM behaviour; both can coexist (see chain.ts —
//! `ttsBackend` already follows this pattern with `'macsay' | 'pneuma-tts'`).

#![allow(dead_code)] // Skeleton — `lib.rs` does not export this yet.

use std::cell::RefCell;
use std::fmt;

use crate::matvec_memo;

/// Configuration for the windowed Q-Former adapter.
///
/// Defaults target the qwen-coder-7b mesh; override `output_dim` if you
/// wire this against a different LLM (e.g. 5376 for gemma4-31b-it; the
/// canonical dim list lives in `project_gemma4_ssot.md`).
#[derive(Debug, Clone)]
pub struct SpeechAdapterConfig {
    /// Number of learnable query tokens. The output sequence length is
    /// fixed to this number — this is the temporal downsampler. Granite
    /// uses 60; we default to 64 (power of two, easier batching).
    pub num_query_tokens: usize,
    /// Number of stacked Q-Former layers (cross-attn + FFN per layer).
    pub num_layers: usize,
    /// Internal hidden dim used by queries and the Q-Former trunk.
    pub hidden_dim: usize,
    /// Acoustic encoder output dim. Default 384 = whisper-tiny / -base.
    /// Use 512 for whisper-small, 768 for -medium, 1280 for -large.
    pub acoustic_dim: usize,
    /// LLM token-embedding dim. Default 3584 = qwen-coder-7b.
    pub output_dim: usize,
}

impl Default for SpeechAdapterConfig {
    fn default() -> Self {
        Self {
            num_query_tokens: 64,
            num_layers: 2,
            hidden_dim: 768,
            acoustic_dim: 384,
            output_dim: 3584,
        }
    }
}

/// One Q-Former block: cross-attention from queries → frames, then a
/// small position-wise FFN. We keep the FFN at hidden_dim → hidden_dim
/// (no expansion ratio) so the parameter count of the skeleton stays
/// predictable; the real Granite block uses 4× expansion.
#[derive(Debug, Clone)]
struct QFormerBlock {
    /// Query projection: (hidden_dim, hidden_dim), row-major.
    w_q: Vec<f32>,
    /// Key projection from acoustic frames: (hidden_dim, acoustic_dim).
    w_k: Vec<f32>,
    /// Value projection from acoustic frames: (hidden_dim, acoustic_dim).
    w_v: Vec<f32>,
    /// Output projection: (hidden_dim, hidden_dim).
    w_o: Vec<f32>,
    /// FFN: (hidden_dim, hidden_dim).
    w_ffn: Vec<f32>,
}

/// Granite-style modality adapter.
///
/// Holds the learnable queries (K, H), the per-layer Q-Former weights,
/// and the final (H → output_dim) projection.
pub struct SpeechAdapter {
    cfg: SpeechAdapterConfig,
    /// Learnable queries flattened row-major, shape (K, hidden_dim).
    queries: Vec<f32>,
    blocks: Vec<QFormerBlock>,
    /// Final projection into LLM embedding space: (output_dim, hidden_dim).
    w_proj: Vec<f32>,
    /// Exact resident memo for repeated F32 adapter projections.
    memo: RefCell<matvec_memo::MatVecMemo>,
}

impl fmt::Debug for SpeechAdapter {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("SpeechAdapter")
            .field("cfg", &self.cfg)
            .field("queries", &self.queries)
            .field("blocks", &self.blocks)
            .field("w_proj", &self.w_proj)
            .finish_non_exhaustive()
    }
}

impl Clone for SpeechAdapter {
    fn clone(&self) -> Self {
        Self {
            cfg: self.cfg.clone(),
            queries: self.queries.clone(),
            blocks: self.blocks.clone(),
            w_proj: self.w_proj.clone(),
            memo: RefCell::new(new_exact_adapter_memo()),
        }
    }
}

impl SpeechAdapter {
    /// Construct a new adapter with deterministic weights derived from
    /// `seed`. Use the same seed in tests to assert determinism; in
    /// production this constructor will be replaced by a `.knot` loader
    /// (see STUBBED notes at the top of the file).
    pub fn new(cfg: SpeechAdapterConfig, seed: u64) -> Self {
        let k = cfg.num_query_tokens;
        let h = cfg.hidden_dim;
        let a = cfg.acoustic_dim;
        let o = cfg.output_dim;

        let mut rng = SplitMix64::new(seed);
        let queries = rng.fill(k * h, 0.02);

        let blocks: Vec<QFormerBlock> = (0..cfg.num_layers)
            .map(|_| QFormerBlock {
                w_q: rng.fill(h * h, 0.02),
                w_k: rng.fill(h * a, 0.02),
                w_v: rng.fill(h * a, 0.02),
                w_o: rng.fill(h * h, 0.02),
                w_ffn: rng.fill(h * h, 0.02),
            })
            .collect();

        let w_proj = rng.fill(o * h, 0.02);

        Self {
            cfg,
            queries,
            blocks,
            w_proj,
            memo: RefCell::new(new_exact_adapter_memo()),
        }
    }

    /// Adapter shape contract.
    pub fn output_shape(&self) -> (usize, usize) {
        (self.cfg.num_query_tokens, self.cfg.output_dim)
    }

    /// Enable/disable exact F32 projection memoization.
    pub fn memo_enable(&self, enabled: bool) {
        self.memo.borrow_mut().set_enabled(enabled);
    }

    /// Clear resident projection memo state.
    pub fn memo_clear(&self) {
        self.memo.borrow_mut().clear();
    }

    /// `(hits, misses, evictions)` for resident projection memo state.
    pub fn memo_stats(&self) -> (u64, u64, u64) {
        self.memo.borrow().stats()
    }

    /// Forward pass.
    ///
    /// `frames` is the acoustic encoder output, row-major
    /// `(num_frames, acoustic_dim)`. Returns row-major
    /// `(num_query_tokens, output_dim)` — the LLM-space embeddings the
    /// downstream qwen mesh consumes in place of token embeddings.
    ///
    /// Panics if `frames.len() != num_frames * acoustic_dim`.
    pub fn forward(&self, frames: &[f32], num_frames: usize) -> Vec<f32> {
        assert_eq!(
            frames.len(),
            num_frames * self.cfg.acoustic_dim,
            "SpeechAdapter::forward: frames length must be num_frames * acoustic_dim",
        );

        let h = self.cfg.hidden_dim;
        let a = self.cfg.acoustic_dim;
        let o = self.cfg.output_dim;
        let k = self.cfg.num_query_tokens;
        let scale = 1.0_f32 / (h as f32).sqrt();

        // Working copy of the queries — mutated in-place across blocks.
        let mut q_state = self.queries.clone();

        // Per-block scratch buffers, allocated once and reused. Pneuma's
        // existing kernels (model_whisper_encoder.rs lines 15-18) follow
        // the same "allocate at construction, reuse on forward" pattern;
        // a future revision should hoist these into the struct.
        let mut k_proj = vec![0f32; num_frames * h];
        let mut v_proj = vec![0f32; num_frames * h];
        let mut attn_scores = vec![0f32; num_frames];
        let mut q_proj = vec![0f32; h];
        let mut ctx = vec![0f32; h];

        for (block_idx, block) in self.blocks.iter().enumerate() {
            // Project all acoustic frames once per block — keys + values
            // are reused across every query.
            cached_adapter_matvec(
                &self.memo,
                &mut k_proj,
                frames,
                &block.w_k,
                h,
                a,
                num_frames,
                h,
                block_idx,
                matvec_memo::OP_K,
            );
            cached_adapter_matvec(
                &self.memo,
                &mut v_proj,
                frames,
                &block.w_v,
                h,
                a,
                num_frames,
                h,
                block_idx,
                matvec_memo::OP_V,
            );

            for q_idx in 0..k {
                let q_row = &q_state[q_idx * h..(q_idx + 1) * h];

                // Q projection.
                cached_adapter_matvec(
                    &self.memo,
                    &mut q_proj,
                    q_row,
                    &block.w_q,
                    h,
                    h,
                    1,
                    h,
                    block_idx,
                    matvec_memo::OP_Q,
                );

                // Scaled dot-product attention scores: q · k_t / sqrt(h).
                for t in 0..num_frames {
                    let kt = &k_proj[t * h..(t + 1) * h];
                    attn_scores[t] = dot(&q_proj, kt) * scale;
                }
                softmax(&mut attn_scores);

                // Weighted sum over values → context.
                for x in ctx.iter_mut() {
                    *x = 0.0;
                }
                for t in 0..num_frames {
                    let w = attn_scores[t];
                    let vt = &v_proj[t * h..(t + 1) * h];
                    for j in 0..h {
                        ctx[j] += w * vt[j];
                    }
                }

                // Output projection + residual into q_state.
                let mut out_row = vec![0f32; h];
                cached_adapter_matvec(
                    &self.memo,
                    &mut out_row,
                    &ctx,
                    &block.w_o,
                    h,
                    h,
                    1,
                    h,
                    block_idx,
                    matvec_memo::OP_O,
                );
                let q_dst = &mut q_state[q_idx * h..(q_idx + 1) * h];
                for j in 0..h {
                    q_dst[j] += out_row[j];
                }

                // Position-wise FFN with a GELU-ish nonlinearity (cheap
                // tanh-based approximation; matches the `gelu_inplace`
                // family in math.rs without taking that dep yet).
                let ffn_in = q_dst.to_vec();
                let mut ffn_out = vec![0f32; h];
                cached_adapter_matvec(
                    &self.memo,
                    &mut ffn_out,
                    &ffn_in,
                    &block.w_ffn,
                    h,
                    h,
                    1,
                    h,
                    block_idx,
                    matvec_memo::OP_FFN_DOWN,
                );
                for x in ffn_out.iter_mut() {
                    *x = gelu_approx(*x);
                }
                for j in 0..h {
                    q_dst[j] += ffn_out[j];
                }
            }
        }

        // Final linear projection into LLM embedding space.
        let mut out = vec![0f32; k * o];
        for q_idx in 0..k {
            let q_row = &q_state[q_idx * h..(q_idx + 1) * h];
            cached_adapter_matvec(
                &self.memo,
                &mut out[q_idx * o..(q_idx + 1) * o],
                q_row,
                &self.w_proj,
                o,
                h,
                1,
                o,
                self.cfg.num_layers,
                matvec_memo::OP_OUTPUT_PROJ,
            );
        }
        out
    }
}

// -- local math helpers -------------------------------------------------
//
// Deliberately self-contained so the file has zero new dependencies.
// Once integrated, swap these for `crate::math::{mat_vec_f32, softmax,
// dot_product}` and `crate::math::gelu_inplace`.

fn new_exact_adapter_memo() -> matvec_memo::MatVecMemo {
    let mut memo = matvec_memo::MatVecMemo::new();
    memo.set_enabled(true);
    memo.set_tau_squared(0.0);
    memo
}

fn adapter_matvec_dispatch(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
) {
    for b in 0..n_batch {
        matvec(
            &mut out[b * out_stride..b * out_stride + rows],
            &x[b * cols..b * cols + cols],
            w,
            rows,
            cols,
        );
    }
}

fn cached_adapter_matvec(
    memo: &RefCell<matvec_memo::MatVecMemo>,
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
    layer: usize,
    op: u8,
) {
    matvec_memo::cached_mat_vec_f32(
        &mut memo.borrow_mut(),
        out,
        x,
        w,
        rows,
        cols,
        n_batch,
        out_stride,
        layer,
        op,
        adapter_matvec_dispatch,
    );
}

fn matvec(out: &mut [f32], x: &[f32], w: &[f32], n: usize, d: usize) {
    debug_assert_eq!(out.len(), n);
    debug_assert_eq!(x.len(), d);
    debug_assert_eq!(w.len(), n * d);
    for i in 0..n {
        let row = &w[i * d..(i + 1) * d];
        let mut acc = 0.0_f32;
        for j in 0..d {
            acc += row[j] * x[j];
        }
        out[i] = acc;
    }
}

fn dot(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), b.len());
    let mut acc = 0.0_f32;
    for i in 0..a.len() {
        acc += a[i] * b[i];
    }
    acc
}

fn softmax(x: &mut [f32]) {
    let mut m = f32::NEG_INFINITY;
    for &v in x.iter() {
        if v > m {
            m = v;
        }
    }
    let mut s = 0.0_f32;
    for v in x.iter_mut() {
        *v = (*v - m).exp();
        s += *v;
    }
    if s > 0.0 {
        let inv = 1.0 / s;
        for v in x.iter_mut() {
            *v *= inv;
        }
    }
}

fn gelu_approx(x: f32) -> f32 {
    // tanh-based GELU; same approximation Whisper / Qwen use.
    let c = (2.0_f32 / std::f32::consts::PI).sqrt();
    0.5 * x * (1.0 + (c * (x + 0.044715 * x * x * x)).tanh())
}

/// Tiny deterministic PRNG for skeleton weights. Replaced by knot
/// loader in a follow-up.
struct SplitMix64 {
    state: u64,
}

impl SplitMix64 {
    fn new(seed: u64) -> Self {
        Self {
            state: seed.wrapping_add(0x9E37_79B9_7F4A_7C15),
        }
    }
    fn next_u64(&mut self) -> u64 {
        self.state = self.state.wrapping_add(0x9E37_79B9_7F4A_7C15);
        let mut z = self.state;
        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
        z ^ (z >> 31)
    }
    fn next_f32_unit(&mut self) -> f32 {
        // Map to [-1, 1)
        let v = (self.next_u64() >> 40) as f32 / (1u32 << 24) as f32;
        v * 2.0 - 1.0
    }
    fn fill(&mut self, n: usize, scale: f32) -> Vec<f32> {
        (0..n).map(|_| self.next_f32_unit() * scale).collect()
    }
}

// -- tests --------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;

    /// Default-shape config produces (K, output_dim) regardless of frame
    /// count. This is the temporal-downsampling shape contract the rest
    /// of the chain depends on.
    ///
    /// Uses the default acoustic_dim/output_dim but a smaller hidden_dim
    /// + K so debug-mode rustc finishes the cross-attention sweep in
    /// seconds rather than minutes; the shape invariant is dim-agnostic.
    #[test]
    fn output_shape_is_fixed_regardless_of_frames() {
        let cfg = SpeechAdapterConfig {
            num_query_tokens: 16,
            num_layers: 2,
            hidden_dim: 128,
            acoustic_dim: 384,
            output_dim: 3584,
        };
        let adapter = SpeechAdapter::new(cfg.clone(), 0xC0FFEE);

        for &t in &[100usize, 500, 1500] {
            let frames = vec![0.01_f32; t * cfg.acoustic_dim];
            let out = adapter.forward(&frames, t);
            assert_eq!(
                out.len(),
                cfg.num_query_tokens * cfg.output_dim,
                "wrong output length for {} frames",
                t,
            );
        }
        assert_eq!(adapter.output_shape(), (16, 3584));

        // Confirm Default still wires the qwen-coder-7b output dim.
        let default_adapter = SpeechAdapter::new(SpeechAdapterConfig::default(), 0);
        assert_eq!(default_adapter.output_shape(), (64, 3584));
    }

    /// `num_query_tokens = K` ⇒ output is (K, output_dim) for any K.
    /// Exercises the K parameter independently of the rest of the
    /// config (paranoid: catches a future refactor wiring K through a
    /// constant by mistake).
    #[test]
    fn num_query_tokens_drives_output_rows() {
        let acoustic_dim = 384;
        let output_dim = 3584;
        let num_frames = 200;
        let frames = vec![0.005_f32; num_frames * acoustic_dim];

        for &k in &[1usize, 8, 32, 60, 64, 128] {
            let cfg = SpeechAdapterConfig {
                num_query_tokens: k,
                num_layers: 1,
                hidden_dim: 256,
                acoustic_dim,
                output_dim,
            };
            let adapter = SpeechAdapter::new(cfg.clone(), 42);
            let out = adapter.forward(&frames, num_frames);
            assert_eq!(out.len(), k * output_dim, "K={} produced wrong length", k);
        }
    }

    /// Same seed + same input ⇒ bit-identical output. Catches any
    /// nondeterminism (parallel reduction order, allocator-derived
    /// state, etc.) sneaking into the forward pass.
    #[test]
    fn forward_is_deterministic_on_same_input() {
        let cfg = SpeechAdapterConfig {
            num_query_tokens: 16,
            num_layers: 2,
            hidden_dim: 128,
            acoustic_dim: 384,
            output_dim: 512,
        };
        let a = SpeechAdapter::new(cfg.clone(), 0xDEAD_BEEF);
        let b = SpeechAdapter::new(cfg.clone(), 0xDEAD_BEEF);

        let num_frames = 300;
        let mut frames = vec![0f32; num_frames * cfg.acoustic_dim];
        // Some structured input (sin pattern) so we'd notice if any pass
        // reordered floats.
        for i in 0..frames.len() {
            frames[i] = ((i as f32) * 0.001).sin() * 0.1;
        }

        let out_a = a.forward(&frames, num_frames);
        let out_b = b.forward(&frames, num_frames);

        assert_eq!(out_a.len(), out_b.len());
        for (i, (x, y)) in out_a.iter().zip(out_b.iter()).enumerate() {
            assert_eq!(x.to_bits(), y.to_bits(), "divergence at index {}", i);
        }

        // Sanity: the output is finite (no NaN/Inf poisoning the chain).
        for (i, v) in out_a.iter().enumerate() {
            assert!(v.is_finite(), "non-finite output at index {}: {}", i, v);
        }
    }

    #[test]
    fn forward_reuses_resident_projection_memo_on_identical_input() {
        let cfg = SpeechAdapterConfig {
            num_query_tokens: 4,
            num_layers: 1,
            hidden_dim: 32,
            acoustic_dim: 24,
            output_dim: 48,
        };
        let adapter = SpeechAdapter::new(cfg.clone(), 0x51A7E);
        let num_frames = 12;
        let frames = vec![0.01_f32; num_frames * cfg.acoustic_dim];

        let cold = adapter.forward(&frames, num_frames);
        let (cold_hits, cold_misses, cold_evictions) = adapter.memo_stats();
        assert!(cold_misses > 0);
        assert_eq!(cold_evictions, 0);

        let warm = adapter.forward(&frames, num_frames);
        let (warm_hits, warm_misses, warm_evictions) = adapter.memo_stats();
        assert_eq!(warm, cold);
        assert!(
            warm_hits > cold_hits,
            "identical second forward should produce resident memo hits"
        );
        assert_eq!(
            warm_misses, cold_misses,
            "identical second forward should not add misses"
        );
        assert_eq!(warm_evictions, cold_evictions);
    }
}
